={{ (() => {
  const items = $items('📊 Read All Analytics') || [];
  const rows = items.map(i => i.json).filter(r => r['Total Views']);

  if (rows.length === 0) return JSON.stringify({ has_data: false });

  const totalViews = rows.reduce((s, r) => s + (parseInt(r['Total Views']) || 0), 0);
  const totalLikes = rows.reduce((s, r) => s + (parseInt(r['Likes']) || 0), 0);
  const totalComments = rows.reduce((s, r) => s + (parseInt(r['Comments']) || 0), 0);
  const totalShares = rows.reduce((s, r) => s + (parseInt(r['Shares']) || 0), 0);
  const avgViews = Math.round(totalViews / rows.length);
  const avgEngagement = totalViews > 0 ? (((totalLikes + totalComments + totalShares) / totalViews) * 100).toFixed(2) : '0';
  const viralCount = rows.filter(r => (r['Tier'] || '').includes('VIRAL')).length;
  const videosPublished = rows.length;

  // Platform breakdown
  const platforms = {};
  rows.forEach(r => {
    const p = r['Top Platform'] || 'Unknown';
    platforms[p] = (platforms[p] || 0) + 1;
  });
  const topPlatform = Object.entries(platforms).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A';

  // Last 30 days stats
  const cutoff30 = new Date();
  cutoff30.setDate(cutoff30.getDate() - 30);
  const last30 = rows.filter(r => new Date(r['Date']) >= cutoff30);
  const views30 = last30.reduce((s, r) => s + (parseInt(r['Total Views']) || 0), 0);

  return JSON.stringify({
    has_data: true,
    lifetime_views: totalViews,
    lifetime_likes: totalLikes,
    lifetime_comments: totalComments,
    lifetime_shares: totalShares,
    videos_published: videosPublished,
    avg_views_per_video: avgViews,
    avg_engagement_rate: avgEngagement + '%',
    viral_videos: viralCount,
    viral_rate: videosPublished > 0 ? ((viralCount / videosPublished) * 100).toFixed(1) + '%' : '0%',
    top_platform: topPlatform,
    views_last_30_days: views30,
    date_generated: new Date().toISOString().split('T')[0]
  });
})() }}

